func (r *responseWriter) Flush() {
	if !r.seenData {

		return
	}

	if r.compressionDisabled {
		if rw, ok := r.rw.(http.Flusher); ok {
			rw.Flush()
		}

		return
	}

	if !r.compressionStarted {
		return
	}

	defer func() {

		_ = r.compressionWriter.Flush()

		if rw, ok := r.rw.(http.Flusher); ok {
			rw.Flush()
		}
	}()

	n, err := r.compressionWriter.Write(r.buf)
	if err != nil {
		return
	}

	if n < len(r.buf) {
		r.buf = r.buf[n:]
		return
	}

	r.buf = r.buf[:0]
}
